if doc.external_work_history:
    for work_history in doc.external_work_history:
        if work_history.custom_from_date and work_history.custom_to_date:
            if frappe.utils.getdate(work_history.custom_to_date) <= frappe.utils.getdate(work_history.custom_from_date):
                frappe.throw("To Date must be greater than From Date")

if doc.custom_employee_advance:
    if doc.grand_total > float(doc.custom_advance_amount):
        frappe.throw("Grand Total cannot be greater than Current Balance ")

if not doc.custom_full_name.replace(" ", "").isalpha():
    frappe.throw("Full Name must contain only letters and spaces.")

if doc.custom_phone_no and doc.custom_emergency_phone_no:
    if not doc.custom_phone_no.isdigit():
        frappe.throw("Phone Number must contain only numbers.")
    if not doc.custom_emergency_phone_no.isdigit():
        frappe.throw("Phone Number must contain only numbers.")
